mapper.update:
UPDATE rest_logs
SET rest_type_id = #{restTypeId}, place_id = #{placeId},
    start_time = #{startTime}, end_time = #{endTime},
    memo = #{memo}, emotion_before = #{emotionBefore},
    emotion_after = #{emotionAfter}, mood_tags_json = #{moodTagsJson}
WHERE id = #{id}

mapper.select:
SELECT ra.id, ra.activity_name AS title, rt.type_name AS category, ra.duration_minutes AS duration, ra.guide_content AS guideContent FROM rest_activities ra JOIN rest_types rt ON ra.rest_type_id = rt.id
rt.type_name = #{category}
ORDER BY rt.id, ra.id
